module bitwise_xor (
    input [7:0] A,
    input [7:0] B,
    input enable,
    output reg [7:0] result
);
  wire [7:0] _tap_A = A & {8{1'b1}};


    always @ (A, B, enable) begin
        if (enable) begin
            result = A ^ B;
        end
        else begin
            result = 8'b0;
        end
    end

endmodule
